__global__ void fused_matmul(float* A, float* B, float* C, int M, int N, int K) {
    int row = blockIdx.y * 8 + threadIdx.y;
    int col_base = (blockIdx.x * 32 + threadIdx.x) * 4;
    __shared__ float As[1032];
    int sr = threadIdx.y;
    float acc0 = 0.0f;
    float acc1 = 0.0f;
    float acc2 = 0.0f;
    float acc3 = 0.0f;
    for (int tile_k = 0; tile_k < K; tile_k += 128) {
        for (int a_s = threadIdx.x; a_s < 128; a_s += 32) {
            As[sr * 129 + a_s] = ((row < M && tile_k + a_s < K) ? (A[row * K + (tile_k + a_s)]) : (0.0f));
        }
        __syncthreads();
        if (col_base + 3 < N && N % 4 == 0) {
            #pragma unroll
            for (int kk = 0; kk < 128; kk++) {
                float a_val = As[sr * 129 + kk];
                float4 b4 = *reinterpret_cast<float4*>(&B[(tile_k + kk) * N + col_base]);
                acc0 += a_val * b4.x;
                acc1 += a_val * b4.y;
                acc2 += a_val * b4.z;
                acc3 += a_val * b4.w;
            }
        } else {
            if (col_base < N) {
                for (int kk = 0; kk < 128; kk++) {
                    float a_val = As[sr * 129 + kk];
                    if (col_base + 0 < N) {
                        acc0 += a_val * B[(tile_k + kk) * N + (col_base + 0)];
                    }
                    if (col_base + 1 < N) {
                        acc1 += a_val * B[(tile_k + kk) * N + (col_base + 1)];
                    }
                    if (col_base + 2 < N) {
                        acc2 += a_val * B[(tile_k + kk) * N + (col_base + 2)];
                    }
                    if (col_base + 3 < N) {
                        acc3 += a_val * B[(tile_k + kk) * N + (col_base + 3)];
                    }
                }
            }
        }
        __syncthreads();
    }
    if (row < M && col_base + 0 < N) {
        C[row * N + (col_base + 0)] = acc0;
    }
    if (row < M && col_base + 1 < N) {
        C[row * N + (col_base + 1)] = acc1;
    }
    if (row < M && col_base + 2 < N) {
        C[row * N + (col_base + 2)] = acc2;
    }
    if (row < M && col_base + 3 < N) {
        C[row * N + (col_base + 3)] = acc3;
    }
}
